+        (U64, I32 | I64) | (I32 | I64, U64) => F64,
         (I32, U32) | (U32, I32) => I64,
         (I64, U32) | (U32, I64) => I64,
         (I64, _) | (_, I64) => I64,
@@ -293,6 +293,8 @@ mod tests {
     fn test_type_promotion_matrix_unsigned() {
         assert_eq!(promote_dtype(DType::Bool, DType::U32), DType::U32);
         assert_eq!(promote_dtype(DType::U32, DType::U64), DType::U64);
